/**
 * The Void — Game Coordinate Tests
 *
 * Verifies the universal coordinate system:
 * - Round-trip encode/decode
 * - Deterministic tile seed derivation
 * - Cube coordinate constraint (q + r + s = 0)
 * - Hex movement and distance
 * - Gnosis time dilation per dimension
 */

import { describe, it, expect } from 'vitest';
import {
  createGameCoordinate,
  originCoordinate,
  isValidCoordinate,
  coordinateEquals,
  coordinateSpatialEquals,
  hexDistance,
  moveCoordinate,
  changeDimension,
  getNeighbors,
  encodeGameCoordinate,
  decodeGameCoordinate,
  coordinateToTileSeed,
  coordinateToString,
  HEX_DIRECTIONS,
} from '../void-game-coordinate';
import { DIMENSION_TIME_DILATION, type DimensionIndex } from '../void-game-types';

describe('void-game-coordinate', () => {
  // ── Construction ────────────────────────────────────────────────

  describe('createGameCoordinate', () => {
    it('enforces cube constraint q + r + s = 0', () => {
      const coord = createGameCoordinate(42, 3, 1, -1, 0);
      expect(coord.hexQ + coord.hexR + coord.hexS).toBe(0);
      expect(coord.hexS).toBe(0); // -1 - (-1) = 0
    });

    it('computes hexS from q and r', () => {
      const coord = createGameCoordinate(42, 3, 3, -2, 0);
      expect(coord.hexS).toBe(-1); // -(3 + (-2)) = -1
    });

    it('freezes the coordinate object', () => {
      const coord = createGameCoordinate(42, 3, 0, 0, 0);
      expect(Object.isFrozen(coord)).toBe(true);
    });
  });

  describe('originCoordinate', () => {
    it('starts at dimension 0, position (0,0,0), tick 0', () => {
      const origin = originCoordinate(42);
      expect(origin.seed).toBe(42);
      expect(origin.dimension).toBe(0);
      expect(origin.hexQ).toBe(0);
      expect(origin.hexR).toBe(0);
      expect(origin.hexS).toBe(0);
      expect(origin.tick).toBe(0);
    });
  });

  // ── Validation ──────────────────────────────────────────────────

  describe('isValidCoordinate', () => {
    it('accepts valid coordinates', () => {
      expect(isValidCoordinate(createGameCoordinate(1, 0, 0, 0, 0))).toBe(true);
      expect(isValidCoordinate(createGameCoordinate(100, 9, 5, -3, 42))).toBe(true);
    });

    it('rejects dimension out of range', () => {
      const bad = { seed: 1, dimension: 13 as unknown as DimensionIndex, hexQ: 0, hexR: 0, hexS: 0, tick: 0 };
      expect(isValidCoordinate(bad)).toBe(false);
    });

    it('rejects negative seed', () => {
      const bad = { seed: -1, dimension: 0 as const, hexQ: 0, hexR: 0, hexS: 0, tick: 0 };
      expect(isValidCoordinate(bad)).toBe(false);
    });
  });

  // ── Equality ────────────────────────────────────────────────────

  describe('coordinateEquals', () => {
    it('returns true for identical coordinates', () => {
      const a = createGameCoordinate(42, 3, 1, -1, 5);
      const b = createGameCoordinate(42, 3, 1, -1, 5);
      expect(coordinateEquals(a, b)).toBe(true);
    });

    it('returns false for different ticks', () => {
      const a = createGameCoordinate(42, 3, 1, -1, 5);
      const b = createGameCoordinate(42, 3, 1, -1, 6);
      expect(coordinateEquals(a, b)).toBe(false);
    });
  });

  describe('coordinateSpatialEquals', () => {
    it('ignores tick for spatial equality', () => {
      const a = createGameCoordinate(42, 3, 1, -1, 5);
      const b = createGameCoordinate(42, 3, 1, -1, 999);
      expect(coordinateSpatialEquals(a, b)).toBe(true);
    });
  });

  // ── Hex Arithmetic ──────────────────────────────────────────────

  describe('hexDistance', () => {
    it('returns 0 for same position', () => {
      const a = createGameCoordinate(42, 3, 0, 0, 0);
      expect(hexDistance(a, a)).toBe(0);
    });

    it('returns 1 for adjacent tiles', () => {
      const a = createGameCoordinate(42, 3, 0, 0, 0);
      const b = createGameCoordinate(42, 3, 1, -1, 0);
      expect(hexDistance(a, b)).toBe(1);
    });

    it('returns correct distance for distant tiles', () => {
      const a = createGameCoordinate(42, 3, 0, 0, 0);
      const b = createGameCoordinate(42, 3, 3, -2, 0);
      expect(hexDistance(a, b)).toBe(3);
    });
  });

  describe('HEX_DIRECTIONS', () => {
    it('has exactly 6 directions', () => {
      expect(HEX_DIRECTIONS).toHaveLength(6);
    });

    it('all directions satisfy cube constraint', () => {
      for (const [dq, dr, ds] of HEX_DIRECTIONS) {
        expect(dq + dr + ds).toBe(0);
      }
    });
  });

  describe('moveCoordinate', () => {
    it('moves in the correct hex direction', () => {
      const origin = originCoordinate(42);
      // Move East: [1, 0, -1]
      const moved = moveCoordinate(origin, 0);
      expect(moved.hexQ).toBe(1);
      expect(moved.hexR).toBe(0);
      expect(moved.hexS).toBe(-1);
    });

    it('maintains cube constraint after move', () => {
      const origin = originCoordinate(42);
      for (let i = 0; i < 6; i++) {
        const moved = moveCoordinate(origin, i);
        expect(moved.hexQ + moved.hexR + moved.hexS).toBe(0);
      }
    });

    it('advances gnosis time by β₁ per move', () => {
      // Dimension 3 (Proton): β₁ = 3 pLo per action
      const proton = createGameCoordinate(42, 3, 0, 0, 0);
      const moved = moveCoordinate(proton, 0);
      expect(moved.tick).toBe(3);

      // Dimension 5 (Emanations): β₁ = 6 pLo per action
      const emanations = createGameCoordinate(42, 5, 0, 0, 0);
      const movedEm = moveCoordinate(emanations, 0);
      expect(movedEm.tick).toBe(6);
    });

    it('time does not advance in Bythos (dimension 0)', () => {
      const bythos = originCoordinate(42);
      const moved = moveCoordinate(bythos, 0);
      expect(moved.tick).toBe(0); // Bythos is timeless
    });

    it('wraps direction index modulo 6', () => {
      const origin = originCoordinate(42);
      const moved6 = moveCoordinate(origin, 6);
      const moved0 = moveCoordinate(origin, 0);
      expect(coordinateSpatialEquals(moved6, moved0)).toBe(true);
    });
  });

  describe('getNeighbors', () => {
    it('returns exactly 6 neighbors', () => {
      const origin = originCoordinate(42);
      const neighbors = getNeighbors(origin);
      expect(neighbors).toHaveLength(6);
    });

    it('all neighbors are distance 1', () => {
      const origin = originCoordinate(42);
      for (const neighbor of getNeighbors(origin)) {
        expect(hexDistance(origin, neighbor)).toBe(1);
      }
    });
  });

  describe('changeDimension', () => {
    it('changes dimension without moving spatially', () => {
      const coord = createGameCoordinate(42, 3, 5, -3, 10);
      const ascended = changeDimension(coord, 4);
      expect(ascended.dimension).toBe(4);
      expect(ascended.hexQ).toBe(5);
      expect(ascended.hexR).toBe(-3);
      expect(ascended.hexS).toBe(coord.hexS);
      expect(ascended.tick).toBe(10);
    });
  });

  // ── Binary Encoding ─────────────────────────────────────────────

  describe('encode/decode round-trip', () => {
    it('round-trips the origin coordinate', () => {
      const origin = originCoordinate(42);
      const buffer = encodeGameCoordinate(origin);
      const decoded = decodeGameCoordinate(buffer);
      expect(coordinateEquals(origin, decoded)).toBe(true);
    });

    it('round-trips a complex coordinate', () => {
      const coord = createGameCoordinate(999999, 7, -15, 8, 123.456);
      const buffer = encodeGameCoordinate(coord);
      expect(buffer.byteLength).toBe(32);
      const decoded = decodeGameCoordinate(buffer);
      expect(decoded.seed).toBe(coord.seed);
      expect(decoded.dimension).toBe(coord.dimension);
      expect(decoded.hexQ).toBe(coord.hexQ);
      expect(decoded.hexR).toBe(coord.hexR);
      expect(decoded.hexS).toBe(coord.hexS);
      expect(decoded.tick).toBeCloseTo(coord.tick, 3);
    });

    it('rejects undersized buffers', () => {
      expect(() => decodeGameCoordinate(new ArrayBuffer(16))).toThrow(
        /Buffer too small/
      );
    });
  });

  // ── Deterministic Tile Seed ─────────────────────────────────────

  describe('coordinateToTileSeed', () => {
    it('returns same seed for same coordinate', () => {
      const coord = createGameCoordinate(42, 3, 5, -3, 0);
      const seed1 = coordinateToTileSeed(coord);
      const seed2 = coordinateToTileSeed(coord);
      expect(seed1).toBe(seed2);
    });

    it('returns different seeds for different coordinates', () => {
      const a = createGameCoordinate(42, 3, 5, -3, 0);
      const b = createGameCoordinate(42, 3, 5, -2, 0);
      expect(coordinateToTileSeed(a)).not.toBe(coordinateToTileSeed(b));
    });

    it('returns different seeds for different universe seeds', () => {
      const a = createGameCoordinate(42, 3, 0, 0, 0);
      const b = createGameCoordinate(43, 3, 0, 0, 0);
      expect(coordinateToTileSeed(a)).not.toBe(coordinateToTileSeed(b));
    });

    it('returns value in [0, 1)', () => {
      for (let i = 0; i < 100; i++) {
        const coord = createGameCoordinate(i, 3, i - 50, 50 - i, 0);
        const seed = coordinateToTileSeed(coord);
        expect(seed).toBeGreaterThanOrEqual(0);
        expect(seed).toBeLessThan(1);
      }
    });
  });

  // ── Formatting ──────────────────────────────────────────────────

  describe('coordinateToString', () => {
    it('produces human-readable format', () => {
      const coord = createGameCoordinate(42, 3, 1, -1, 3.14);
      const str = coordinateToString(coord);
      expect(str).toContain('42');
      expect(str).toContain('d3');
      expect(str).toContain('1,-1,0');
      expect(str).toContain('pLo');
    });
  });

  // ── Time Dilation ───────────────────────────────────────────────

  describe('time dilation', () => {
    it('Bythos has zero dilation (timeless)', () => {
      expect(DIMENSION_TIME_DILATION[0]).toBe(0);
    });

    it('symmetry zones have comfortable rates', () => {
      expect(DIMENSION_TIME_DILATION[3]).toBe(3); // Proton
      expect(DIMENSION_TIME_DILATION[5]).toBe(6); // Emanations
    });

    it('dilation equals β₁ for gnostic dimensions', () => {
      expect(DIMENSION_TIME_DILATION[1]).toBe(1);
      expect(DIMENSION_TIME_DILATION[2]).toBe(2);
      expect(DIMENSION_TIME_DILATION[9]).toBe(55);
    });

    it('void dimensions have alien time rates', () => {
      expect(DIMENSION_TIME_DILATION[10]).toBe(-1); // Cross-File: retrograde
      expect(DIMENSION_TIME_DILATION[11]).toBeCloseTo(0.618, 3); // Temporal: φ⁻¹
      expect(DIMENSION_TIME_DILATION[12]).toBeCloseTo(Math.PI, 5); // Data-Plane: irrational
    });
  });
});
